Event bubbling: the event starts at the target element and propagates upward through ancestors to the document. Event capturing: the event starts at the document root and propagates downward to the target. By default, addEventListener listeners fire during the bubbling phase. You can use the third parameter { capture: true } to listen during capturing.

Event delegation uses bubbling to handle events on dynamically created child elements by placing a single listener on a parent element and checking event.target to determine which child triggered the event.

Example: A task list where new tasks are added dynamically. Instead of attaching a click listener to every delete button (which would miss buttons added after the listener was registered), attach one listener to the <ul>:
  taskList.addEventListener('click', (e) => {
    if (e.target.matches('.delete-btn')) {
      e.target.closest('li').remove();
    }
  });

This handles all current and future delete buttons with one listener, uses less memory, and automatically handles dynamically added tasks.

async function getActiveUsersSorted() {
  const response = await fetch('/api/users');
  if (!response.ok) {
    throw new Error(`Failed to fetch users: HTTP ${response.status} ${response.statusText}`);
  }
  const users = await response.json();
  return users
    .filter(user => user.active)
    .sort((a, b) => a.name.localeCompare(b.name));
}

// Usage:
try {
  const activeUsers = await getActiveUsersSorted();
  console.log(activeUsers);
} catch (error) {
  console.error('Error loading users:', error.message);
}

app.post('/api/books', async (req, res, next) => {
  try {
    const { title, isbn } = req.body;
    const errors = [];

    if (!title || typeof title !== 'string' || title.trim().length === 0) {
      errors.push({ field: 'title', message: 'Title is required and must be a non-empty string' });
    }
    if (!isbn || typeof isbn !== 'string' || !/^\d{13}$/.test(isbn)) {
      errors.push({ field: 'isbn', message: 'ISBN must be a 13-digit string' });
    }

    if (errors.length > 0) {
      return res.status(400).json({ error: 'validation_error', details: errors });
    }

