    res.status(201).json(book);
  } catch (error) {
    next(error);
  }
});

GET /api/posts?page=1&limit=10
  Description: List posts with pagination
  Request body: none
  Response: 200 { posts: [...], total: 100, page: 1, limit: 10, hasMore: true }

POST /api/posts
  Description: Create a new post (authenticated)
  Request body: { title: string, content: string, tags: string[] }
  Response: 201 { id, title, content, tags, authorId, createdAt }
  Errors: 400 (validation), 401 (unauthenticated)

GET /api/posts/:id
  Description: Get a single post with its comments
  Request body: none
  Response: 200 { id, title, content, author, createdAt, comments: [...] }
  Errors: 404 (post not found)

POST /api/posts/:id/comments
  Description: Add a comment to a post (authenticated)
  Request body: { content: string }
  Response: 201 { id, content, authorId, postId, createdAt }
  Errors: 400 (validation), 401 (unauthenticated), 404 (post not found)

function BookList() {
  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    async function fetchBooks() {
      try {
        const response = await fetch('/api/books');
        if (!response.ok) {
          throw new Error(`HTTP ${response.status}: ${response.statusText}`);
        }
        const data = await response.json();
        setBooks(data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    }
    fetchBooks();
  }, []);

  if (loading) return <div role='status' aria-label='Loading'>Loading books...</div>;
  if (error) return <div role='alert'>Error: {error}</div>;
  if (books.length === 0) return <p>No books found.</p>;

  return (
    <ul>
      {books.map(book => (
        <li key={book.id}>
          <strong>{book.title}</strong> by {book.author}
        </li>
      ))}
    </ul>
  );
}

useState manages simple, independent state values. useReducer manages complex state where multiple values change together or where the next state depends on the previous state, centralizing all transitions in a pure reducer function.

Scenario: A shopping cart with items, total, discount, and shipping. With useState:
  const [items, setItems] = useState([]);
  const [total, setTotal] = useState(0);
  const [discount, setDiscount] = useState(0);
  const [shipping, setShipping] = useState(0);
  // Every action (add item, remove item, apply coupon) must update multiple states consistently

With useReducer:
  const [cart, dispatch] = useReducer(cartReducer, initialCart);
  dispatch({ type: 'ADD_ITEM', payload: product });
  // The reducer handles updating items, recalculating total, adjusting shipping in one atomic update

useReducer is better here because: (1) All state changes are centralized in the reducer, making transitions predictable and debuggable. (2) State updates are atomic — adding an item updates the items array and recalculates the total in one render, avoiding intermediate inconsistent states. (3) The reducer is a pure function that can be tested independently of React.

import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { describe, it, expect, vi } from 'vitest';
import SearchBar from './SearchBar';

describe('SearchBar', () => {
  it('calls onSearch with the input value when Search is clicked', async () => {
    const user = userEvent.setup();
    const handleSearch = vi.fn();

    render(<SearchBar onSearch={handleSearch} />);

    const input = screen.getByRole('textbox', { name: /search/i });
    const button = screen.getByRole('button', { name: /search/i });

    await user.type(input, 'React');
    await user.click(button);

    expect(handleSearch).toHaveBeenCalledTimes(1);
    expect(handleSearch).toHaveBeenCalledWith('React');
  });
});

CORS (Cross-Origin Resource Sharing) is a browser security mechanism that blocks requests from one origin (protocol + domain + port) to another unless the server explicitly allows it. The frontend (https://app.example.com) and backend (https://api.example.com) are different origins, so the browser blocks the requests.

The fix is on the Express server:

const cors = require('cors');
app.use(cors({
  origin: 'https://app.example.com',
  credentials: true  // needed if using cookies for JWT
}));

This sets the Access-Control-Allow-Origin header to the frontend's domain, telling the browser it is safe to allow the request. credentials: true is needed for cookie-based authentication because browsers do not send cookies with cross-origin requests unless both the server allows it (Access-Control-Allow-Credentials: true) and the client requests it (fetch with credentials: 'include').

Do NOT use origin: '*' (wildcard) in production with credentials, as it disables CORS protection entirely and is not allowed by browsers when credentials are included. Always specify the exact frontend origin.
